let L_plus_k = atoms(one).map(a => [a]);

for (let k = 1; k < maxRank - 1; k++) {
  let K_next = [];

  L_plus_k.forEach(T => {
    atoms(one).forEach(a => {
      if (!T.includes(a)) {
        K_next = cup(K_next, [M_hat(cup(T, [a]))]);
      }
    });
  });

  let changed = true;
  while (changed) {
    changed = false;
    for (let i = 0; i < K_next.length; i++) {
        for (let j = i + 1; j < K_next.length; j++) {
            const intersect = cap(K_next[i], K_next[j]);
            const is_in_L = L_plus_leq_k.some(S => setEquals(S, intersect));

            if (!is_in_L) {
                const merged = M_hat(cup(K_next[i], K_next[j]));
                K_next.splice(j, 1);
                K_next.splice(i, 1);
                K_next = cup(K_next, [merged]);
                changed = true;
                break;
            }
        }
        if (changed) break;
    }
  }

  L_plus_k = K_next;
  L_plus_leq_k = cup(L_plus_leq_k, L_plus_k);
