            output += `Node ${nodes[i]} is not submodular with atom ${foreignAtoms[j]}` + '\n'
            erros = true
          }
        }
    }
    return output !== '' ? output : null
  },
  isAtomic: top => {
    const bad = ideal(top).filter(node => node !== zero).filter(node => !(node === sup(atoms(node))))
    return bad.length ? bad.join('|') : null;
  }
};

// cl_c(T) = A( \bigvee (T \cap A(c)) )
const cl = (c, T) => {
  const intersect = cap(T, atoms(c));
  const supEl = sup(intersect);
  return supEl ? atoms(supEl) : [];
};

// M(a, x) - behebendes Element für den Verband L'
const M_prime = (a, x) => {
  const coatoms = coAtoms(one);
  let result = atoms(x);

  coatoms.forEach(c => {
    if (leq(a, c)) { 
      const xc = inf(x, c);
      const sup_xa = sup(xc, a);
      if (sup_xa) {
        result = cup(result, atoms(sup_xa));
      }
    }
  });
  return result;
};

// \tilde M(T) = \bigcup_{c \in C_L} cl_c(T) 
const M_tilde = (T) => {
  const coatoms = coAtoms(one);
  let result = [];
  coatoms.forEach(c => {
    result = cup(result, cl(c, T));
  });
  return result;
};

// \hat M(T): Iterierter M_tilde-Fixpunkt
const M_hat = (T) => {
  let current = [...T];
  while (true) {
    const next = M_tilde(current);
    if (setEquals(current, next)) {
      return current;
    }
    current = next;
  }
};

// M*(a, x) - \hat M( A(x) \cup {a} )
const M_star = (a, x) => M_hat(cup(atoms(x), [a]));

return { cl, M_prime, M_tilde, M_hat, M_star };
